// ── NAVBAR SCROLL
const navbar = document.getElementById('navbar');
window.addEventListener('scroll', () => {
  navbar.classList.toggle('scrolled', window.scrollY > 40);
}, { passive: true });

// ── PARALLAX HERO
const heroBg = document.getElementById('heroBg');
window.addEventListener('scroll', () => {
  if (window.scrollY < window.innerHeight) {
    heroBg.style.transform = `scale(1.08) translateY(${window.scrollY * 0.25}px)`;
  }
}, { passive: true });

// ── HAMBURGER / MOBILE NAV
const hamburger = document.getElementById('hamburger');
const navOverlay = document.getElementById('navOverlay');
let navOpen = false;

hamburger.addEventListener('click', () => {
  navOpen = !navOpen;
  hamburger.classList.toggle('active', navOpen);
  navOverlay.classList.toggle('open', navOpen);
  document.body.style.overflow = navOpen ? 'hidden' : '';
});

function closeNav() {
  navOpen = false;
  hamburger.classList.remove('active');
  navOverlay.classList.remove('open');
  document.body.style.overflow = '';
}

// ── SCROLL REVEAL
const revealEls = document.querySelectorAll('.reveal, .reveal-left, .reveal-right');
const revealObs = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
      revealObs.unobserve(entry.target);
    }
  });
}, { threshold: 0.08, rootMargin: '0px 0px -48px 0px' });
revealEls.forEach(el => revealObs.observe(el));

// ── STAGGER CHILDREN
document.querySelectorAll('.cat-grid, .menu-grid, .how-grid, .order-options, .halal-strip, .faq-wrap').forEach(parent => {
  Array.from(parent.children).forEach((child, i) => {
    child.style.transitionDelay = `${i * 0.09}s`;
  });
});

// ── COUNTER ANIMATION
function animateCounter(el, target, duration = 1800) {
  let start = null;
  const step = (ts) => {
    if (!start) start = ts;
    const progress = Math.min((ts - start) / duration, 1);
    const eased = 1 - Math.pow(1 - progress, 3);
    el.textContent = Math.round(eased * target);
    if (progress < 1) requestAnimationFrame(step);
  };
  requestAnimationFrame(step);
}

const counterObs = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      const target = parseInt(entry.target.dataset.target);
      if (!isNaN(target)) animateCounter(entry.target, target);
      counterObs.unobserve(entry.target);
    }
  });
}, { threshold: 0.5 });

document.querySelectorAll('[data-target]').forEach(el => counterObs.observe(el));

// ── FAQ ACCORDION
document.querySelectorAll('.faq-question').forEach(btn => {
  btn.addEventListener('click', () => {
    const item = btn.closest('.faq-item');
    const isOpen = item.classList.contains('open');
    document.querySelectorAll('.faq-item.open').forEach(i => {
      i.classList.remove('open');
      i.querySelector('.faq-question').setAttribute('aria-expanded', 'false');
    });
    if (!isOpen) {
      item.classList.add('open');
      btn.setAttribute('aria-expanded', 'true');
    }
  });
});

document.querySelectorAll('.nav-overlay a').forEach(link => {
  link.addEventListener('click', () => {
    if (typeof closeNav === 'function') closeNav();
  });
});
